import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import response from './response.json';

interface Team {
  team: string;
  wins: number;
  losses: number;
  points: number;
}

interface LeagueData {
  leagueName: string;
  topTeams: Team[];
}

export default function Widget() {
  const leagueData = response.data as LeagueData;
  const { leagueName, topTeams } = leagueData;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: 'rgba(30, 41, 59, 0.8)',
        backdropFilter: 'blur(8px)',
        borderRadius: 2,
      }}
      elevation={3}
    >
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
              {leagueName}
            </Typography>
            <Typography variant="body2" sx={{ color: '#94A3B8', mb: 1 }}>
              Top Teams
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {topTeams.map((team) => (
                <Chip
                  key={team.team}
                  label={`${team.team} (${team.points} pts)`}
                  sx={{
                    bgcolor: '#334155',
                    color: '#F8FAFC',
                    fontSize: '11px',
                    px: 1,
                    py: 0.5,
                  }}
                />
              ))}
            </Stack>
          </Box>

          <Stack spacing={1.5}>
            {topTeams.map((team) => (
              <Box key={team.team} sx={{ bgcolor: '#1F2937', p: 1.5, borderRadius: 1 }}>
                <Stack direction="row" justifyContent="space-between" alignItems="center">
                  <Typography variant="body2" sx={{ color: '#F8FAFC', fontWeight: 600 }}>
                    {team.team}
                  </Typography>
                  <Typography variant="body2" sx={{ color: '#F97316', fontWeight: 500 }}>
                    {team.wins}W - {team.losses}L
                  </Typography>
                </Stack>
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
